const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Skip duplicates — only process first occurrence
  if (parseInt(d.row_num) > 1) {
    results.push({
      json: {
        record_id: d.record_id,
        full_name: `${d.first_name} ${d.last_name}`,
        action: 'skipped',
        result: 'duplicate',
        message: 'Duplicate email: ' + d.email,
        skip: true
      }
    });
    continue;
  }

  // Validate required fields
  const missing = [];
  if (!d.first_name) missing.push('first_name');
  if (!d.last_name)  missing.push('last_name');
  if (!d.email)      missing.push('email');
  if (!d.employee_id) missing.push('employee_id');

  if (missing.length > 0) {
    results.push({
      json: {
        record_id: d.record_id,
        full_name: `${d.first_name || ''} ${d.last_name || ''}`.trim(),
        action: 'validation',
        result: 'invalid',
        message: 'Missing: ' + missing.join(', '),
        skip: true
      }
    });
    continue;
  }

  // Normalize email
  const email = (d.email || '').toLowerCase().trim();

  // Normalize phone
  let phone = (d.phone || '').replace(/\s+/g, '');
  if (phone && !phone.startsWith('+')) {
    phone = '+' + phone;
  }

  // Normalize name — title case
  const firstName = (d.first_name || '')
    .trim()
    .charAt(0).toUpperCase() +
    (d.first_name || '').trim().slice(1).toLowerCase();

  const lastName = (d.last_name || '')
    .trim()
    .charAt(0).toUpperCase() +
    (d.last_name || '').trim().slice(1).toLowerCase();

  // Normalize profile URL
  let profileUrl = (d.profile_url || '').trim();
  if (profileUrl && !profileUrl.startsWith('https://')) {
    profileUrl = 'https://' + profileUrl;
  }

  // Reshape for Acumatica format
  results.push({
    json: {
      record_id: d.record_id,
      employee_id: d.employee_id,
      first_name: firstName,
      last_name: lastName,
      full_name: `${firstName} ${lastName}`,
      email: email,
      phone: phone,
      department: d.department || 'General',
      job_title: d.job_title || 'Employee',
      profile_url: profileUrl,
      // Acumatica formatted payload
      acumatica_payload: {
        EmployeeID: { value: d.employee_id },
        Name: { value: `${firstName} ${lastName}` },
        Email: { value: email },
        Phone: { value: phone },
        Department: { value: d.department },
        Position: { value: d.job_title },
        Status: { value: 'Active' }
      },
      skip: false,
      processed_at: new Date().toISOString()
    }
  });
}

return results;

const items = $input.all();

// Safe fallback for original node
let original = {};
try {
  original = $('Validate and Reshape').first()?.json || {};
} catch (e) {
  original = {};
}

return items.map(item => {
  const d = item.json;

  // Extract values safely from Acumatica-style response
  const employeeId = d.EmployeeID?.value || original.employee_id || '';
  const name = d.Name?.value || original.full_name || '';
  const email = d.Email?.value || original.email || '';
  const phone = d.Phone?.value || '';
  const department = d.Department?.value || original.department || '';
  const position = d.Position?.value || original.job_title || '';
  const status = d.Status?.value || 'Unknown';

  // Success check
  const isSuccess = d.id !== undefined;

  // Generate reference
  const acuRef = isSuccess
    ? `ACU-${d.id || Date.now()}`
    : null;

  return {
    json: {
      record_id: original.record_id || `REC-${Date.now()}`,
      employee_id: employeeId,
      full_name: name,
      email: email,
      phone: phone,
      department: department,
      job_title: position,
      status: status,

      // Sync info
      acumatica_ref: acuRef,
      sync_status: isSuccess ? 'synced' : 'failed',
      error: isSuccess ? '' : 'Acumatica call failed',

      synced_at: new Date().toISOString()
    }
  };
});
